import test from "node:test";
import assert from "node:assert";
import { tokenize } from "../src/lexer.js";
import { parse } from "../src/parser.js";
import { analyze } from "../src/analyzer.js";
import { generate } from "../src/generator.js";

const HEADER = `// Generated by BN Script Compiler v0.1
// Source: test.bn
// Do not edit this file directly.`;

function compileSource(source) {
  const ast = parse(tokenize(source, "test.bn"), {
    filename: "test.bn",
    source,
  });
  analyze(ast, {
    filename: "test.bn",
    source,
  });
  return generate(ast);
}

function expected(body) {
  return `${HEADER}\n\n${body}`;
}

test("generator: declaration generation", () => {
  const output = compileSource(`dhori name = "Risat"
sthir age = 25`);

  assert.strictEqual(
    output,
    expected(`let name = "Risat";
const age = 25;`)
  );
});

test("generator: import single output", () => {
  const output = compileSource('amdani { greet } theke "./utils.bn"');

  assert.strictEqual(
    output,
    expected('import { greet } from "./utils.js";')
  );
});

test("generator: import multiple output", () => {
  const output = compileSource(
    'amdani { greet, version } theke "./utils.bn"'
  );

  assert.strictEqual(
    output,
    expected('import { greet, version } from "./utils.js";')
  );
});

test("generator: runtime helper call output", () => {
  const output = compileSource(`dhori user = env("USER")

async kaj main() {
  dhori content = await fileRead("data.txt")
  await fileWrite("out.txt", content)
  await wait(1)
  dhori data = await httpGet("https://example.com")
  ferot data
}`);

  assert.strictEqual(
    output,
    expected(`import * as runtime from "./src/runtime/index.js";

let user = runtime.env("USER");
async function main() {
  let content = await runtime.fileRead("data.txt");
  await runtime.fileWrite("out.txt", content);
  await runtime.wait(1);
  let data = await runtime.httpGet("https://example.com");
  return data;
}`)
  );
});

