test("generator: break and continue in while output", () => {
  const output = compileSource(`dhori i = 0
jotokkhon i < 5 {
  i = i + 1
  jodi i == 2 {
    cholo
  }
  jodi i == 4 {
    bekkhon
  }
  dekhi i
}`);

  assert.strictEqual(
    output,
    expected(`let i = 0;
while (i < 5) {
  i = i + 1;
  if (i === 2) {
    continue;
  }
  if (i === 4) {
    break;
  }
  console.log(i);
}`)
  );
});

